import React, { Component, Fragment } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { hirUtil, simplePaginationConfig, errorNotice, headerActions, headerStrings, breadCrumbActions, SimplePagination, StageHeaderPlane, MyDialog, appActions } from '../../utils';
import { Button, Checkbox, FormControlLabel, IconButton, TableCell, Typography } from '@material-ui/core';
import { CalendarToday, CalendarViewDay, Delete, Edit } from '@material-ui/icons';
import { hirAccountActions } from '../../HIRAccounts';
import { hirRouteNames } from '../../routeNames';
import { MyTable } from '../../utils';
import { HIRButton, HIRStartEndDates } from '../../Includes';
import Calendar from 'react-calendar';
import exportFromJSON from 'export-from-json';


const style = () => ({
    root: {
    },
    cell : {
        padding : 5,
        fontSize : 11,
    },
    iconBtn : {
        padding : 2.5,
    },
    headerContainer : {
        display : 'flex',
        marginBottom : 20,
        alignItems : "center",
    },
    dialogContainer : {
        display : "flex",
        flexDirection : "column",
        alignItems : "center",
        justifyContent : "center"
    },
    download : {
        fontSize : 12,
        textDecoration : "underline",
        "&:hover" : {
            cursor : "pointer",
        }
    }
})
class _HIRDebtHx extends Component {
    constructor(props) {
        super(props);
        this.state = {
            openDialog : false,
            dialogType : null,
            filter : {

            }
        }
        const {dispatch} = props;
        headerActions({
            [headerStrings.headerTitle] : "Debt Settlement",
            [headerStrings.backButtonAction] : null,
        })(dispatch);
        breadCrumbActions.setBreadCrumb([
            {name : "Dashboard", path : hirRouteNames.dashboard},
            {name : "Debt Settlement", path : hirRouteNames.debtors},
        ])(dispatch);
    }
    header = ["ID", "Old ID", "Name", "Gender", "Age", "Phone", "Debt", "Date"];
    headerMapper = ["_id", "oldId", "name", "gender", "age", "phone", "debt", "actionDate"];
    componentDidMount() {
        this.debtorConfig();
    }
    downloadCVS(data){
        const {dispatch} = this.props,
        fileName = 'debt_settlements',
        exportType = 'csv',
        mainData = []
        if(data) for (let i = 0; i < data.length; i++) {
            const dataObject = data[i],
            mainD = {},
            {myProfile} = dataObject?.patient || {}; 
            for (let j = 0; j < this.headerMapper.length; j++) {
                const mapper = this.headerMapper[j];
                let value = dataObject[mapper],
                header = this.header[j];
                switch(mapper){
                    case "actionDate" : 
                        mainD[header] = value && new Date(value).toLocaleDateString(); 
                        break;
                    case "debt" : 
                        mainD[header] = value && new Number(value).toLocaleString(); 
                        break;
                    case "age" : 
                        const age = myProfile && new Date().getFullYear() - new Date(myProfile.dob).getFullYear();
                        mainD[header] = age === 0 ? "< 1" : String(age); 
                        break;
                    case "oldId" : 
                    case "phone" : 
                        mainD[header] = myProfile && myProfile[mapper];
                        break;
                    case "gender" : 
                        mainD[header] = myProfile && myProfile[mapper] && (myProfile[mapper] === "m" ? "Male" : "Female");
                        break;
                    case "_id" : 
                        mainD[header] = dataObject?.patient?._id;
                        break;
                    case "actionDate" : 
                        mainD[header] = new Date(value).toLocaleDateString();
                        break;
                    case "name" : 
                        const {lastName, firstName} = myProfile || {},
                        name = (lastName ? lastName : "") + " " + (firstName ? firstName : "");
                        mainD[header] = name;
                        break;
                    default: mainD[header[j]] = dataObject[mapper]; break;
                }
            }
            mainData.push(mainD);
        }
        appActions.showSnackDialog(
            "You are about to download a CSV file. Do you want to continue?",
            [<Button key="downloadCSV" onClick={()=>{
                appActions.closeSnackDialog()(dispatch);
                exportFromJSON({ data : mainData, fileName, exportType })
            }}>Continue</Button>]
        )(dispatch);
    }
    debtorConfig(){
        this.pageControl = simplePaginationConfig(
            this, this.getDebtHxs, this.props.dispatch,
            "debtors", 50, null, null, this.getDebtHxMinMaxIds,
            this.searchDebtHxs, this.getSearchDebtHxMinMaxIds
        )
        this.pageControl.getAction();
    }
    getFilter(){
        const {filter} = this.state;
        return {...filter, detail : true};
    }
    getDebtHxs = (rows, skip, sort, max, callback)=>dispatch => {
        const filter = this.getFilter();
        hirAccountActions.getDebtHxs(filter, rows, skip, sort, max, callback)(dispatch);
    }
    getDebtHxMinMaxIds = (sort, callback)=> dispatch => {
        const filter = this.getFilter();
        hirAccountActions.getDebtHxMinMaxIds(filter, sort, callback)(dispatch);
    }
    searchDebtHxs = (keyword, rows, skip, sort, max, callback)=>dispatch => {
        const filter = this.getFilter();
        hirAccountActions.searchDebtHxs(filter, keyword, rows, skip, sort, max, callback)(dispatch);
    }
    getSearchDebtHxMinMaxIds = (keyword, sort, callback)=>dispatch => {
        const filter = this.getFilter();
        hirAccountActions.getSearchDebtHxMinMaxIds(filter, keyword, sort, callback)(dispatch);
    }
    cellMapFormat({row, cellMap}){
        const {classes} = this.props,
        {myProfile} = row.patient || {};
        switch(cellMap){
            case "action" : return <TableCell className={classes.cell}>
                {hirUtil.isAdmin() && <div>
                    <IconButton className={classes.iconBtn}
                        onClick={()=>this.setState({openDialog : true, dialogType : "deposit", deposit : row})}
                    >
                        <Edit fontSize="small"/>
                    </IconButton>
                    <IconButton className={classes.iconBtn}
                        onClick={()=>this.deleteDeposit(row)}
                    >
                        <Delete fontSize="small" color="secondary"/>
                    </IconButton>
                </div>}
            </TableCell>
            case "actionDate" : return <TableCell className={classes.cell}>
                {new Date(row[cellMap]).toLocaleDateString()}
            </TableCell>
            case "debt" : return <TableCell className={classes.cell}>
                {row[cellMap] ? Number(row[cellMap]).toLocaleString() : 0}
            </TableCell>
            case "age" : 
                const age = myProfile && new Date().getFullYear() - new Date(myProfile.dob).getFullYear()
                return <TableCell className={classes.cell}>
                    {age === 0 ? "< 1" : String(age)}
                </TableCell>
            case "gender" : return <TableCell className={classes.cell}>
                {myProfile && myProfile[cellMap] && (myProfile[cellMap] === "m" ? "Male" : "Female")}
            </TableCell>
            case "_id" : return <TableCell className={classes.cell}>
                {row?.patient?._id}
            </TableCell>
            case "actionDate" : return <TableCell className={classes.cell}>
                {row[cellMap] && new Date(row[cellMap]).toLocaleDateString()}
            </TableCell>
            case "name" : 
                const {lastName, firstName} = myProfile || {},
                name = (lastName ? lastName : "") + " " + (firstName ? firstName : "");
                return <TableCell className={classes.cell}>
                    {name}
                </TableCell>
            default : return <TableCell className={classes.cell}>
                {myProfile && myProfile[cellMap]}
            </TableCell>
        }
    }
    onMoreClick = row => (e)=> {
        e.stopPropagation();
        const anchorEl = e.target;
        this.setState({anchorEl, debtor : row});
    }
    balanceOutDebt = debtor => {
        const {dispatch} = this.props,
        patientId = debtor._id;
        hirAccountActions.balanceOutDebt(patientId, done => {
            this.setState({anchorEl : null});
            done && this.pageControl.getAction()
        })(dispatch);
    }
    closeDialog = () => this.setState({openDialog : false, dialotType : null, date : null, endDate : null, startDate : null});
    createDeposit(data, callback){
        const {debtor} = this.state,
        {dispatch} = this.props;
        if(!debtor) return errorNotice("No debtor selected", dispatch);
        const {_id : patientId, debt} = debtor,
        {amount} = data;
        if(debt > amount) return errorNotice("The amount stated can't cover the debt! Please increase the amount to match the debt!", dispatch);
        hirAccountActions.createDeposit({...data, patientId}, done => {
            callback && callback();
            if(done){
                this.setState({dialogType : null, openDialog : null})
                this.balanceOutDebt(debtor);
            }
        })(dispatch);
    }
    searchAction = keyword => {
        this.pageControl.search(keyword)
    }
    onChange(e){
        const value = e.target.checked,
        {filter} = this.state;
        this.setState({filter : {...filter, monthOnly : value}},()=>{
            this.pageControl.getAction();
        });
    }
    render() {
        const {classes} = this.props,
        {debtors=[], monthOnly, openDialog, dialogType, dateSearchBtnLoading, date} = this.state;
        const headers = this.header;
        const headerMapper = this.headerMapper;
        let total = 0;

        return (
            <div className={classes.root}>
                <div style={{marginTop : 20, marginBottom : 20}}>
                    <StageHeaderPlane
                        visible={true}
                        searchActions={ this.searchAction.bind(this)}
                        refreshCallback={() => this.setState({filter : {}}, this.debtorConfig.bind(this))}
                        />
                </div>
                <div className={classes.headerContainer}>
                    <IconButton onClick={()=>this.setState({openDialog : true, dialogType : "date"})}>
                        <CalendarToday color="secondary"/>
                    </IconButton>
                    <FormControlLabel
                            value={monthOnly}
                            onChange={this.onChange.bind(this)}
                        control={<Checkbox/>}
                        label={<Typography style={{fontSize : 14}}>Month only view</Typography>}
                    />
                    {hirUtil.isAdmin() && <div><HIRButton
                        type="secondary"
                        onClick={()=>this.setState({openDialog : true, dialogType : "dateRange"})}
                        classes={{btn : classes.marginRight}}
                        >
                            <CalendarViewDay fontSize="small"/>
                            Date Range
                    </HIRButton></div>}
                </div>
                <div>
                    <MyTable
                        id="debt_settlement"
                        header={headers}
                        dataMap={headerMapper}
                        data={debtors}
                        CellMap={this.cellMapFormat.bind(this)}
                    />
                    {this.pageControl && debtors.length > 0 && <div style={{marginTop : 20}}>
                        <SimplePagination
                            nextBtnClick={this.pageControl.nextBtnOnClick()}
                            nextBtnProps={{
                                disabled : this.pageControl.nextBtnDisabled()
                            }}
                            prevBtnClick={this.pageControl.prevBtnOnClick()}
                            prevBtnProps={{
                                disabled : this.pageControl.prevBtnDisabled()
                            }}
                        />
                    </div>}
                    <div style={{display : "flex", justifyContent : "flex-end"}}>
                        <a onClick={()=>this.downloadCVS(debtors)} className={classes.download}>
                            Download CSV file
                        </a>
                    </div>
                </div>
                <MyDialog open={openDialog} within
                 close={this.closeDialog.bind(this)}>
                     <div className={classes.dialogContainer}>
                        {dialogType === "date" && <Fragment>
                                <Typography paragraph className={classes.header}>Search debt settlement by dates</Typography>
                            <Calendar
                                value={date}
                                onChange={date=>this.setState(state=>({filter : {...state.filter, date}}))}/>
                        </Fragment>}
                        {dialogType === "dateRange" && <Fragment>
                            <Typography paragraph className={classes.header}>Search debt settlement by dates range</Typography>
                            <HIRStartEndDates
                                noTitle
                                containerProps={{
                                    style : {
                                        width : "100%"
                                    }
                                }}
                                onDateChange={(startDate, endDate)=>this.setState(state=>({filter : {...state.filter, startDate, endDate}}))}/>
                        </Fragment>}
                        <div style={{marginTop : 20}}>
                            <HIRButton type="primary" 
                                loading={dateSearchBtnLoading}
                                onClick={()=>this.debtorConfig()}>
                                    Get Payments
                                </HIRButton>
                        </div>
                    </div>
                 </MyDialog>           
            </div>
        );
    }
}


_HIRDebtHx.propTypes = {
    classes : PropTypes.object.isRequired
};
export const HIRDebtHx = connect()(withStyles(style)(_HIRDebtHx));
export {HIRDebtHx as default}